// ═══════════════════════════════════════════════════
//  ESPRIT RUNNER — game.js
//  Carte étudiant + sélection personnage + jeu complet
// ═══════════════════════════════════════════════════

// ── CANVAS PRINCIPAL ────────────────────────────────
const canvas = document.getElementById('gameCanvas');
const ctx    = canvas.getContext('2d');
const W = canvas.width;   // 700
const H = canvas.height;  // 420

// ══════════════════════════════════════════════════
//  DONNÉES JOUEUR (carte étudiant)
// ══════════════════════════════════════════════════
// Photo exemple par défaut (Syrine Toumi)
const DEFAULT_PHOTO = "data:image/jpeg;base64,";

let playerData = {
  nom:    '',
  prenom: '',
  classe: '',
  spec:   'GamiX',
  photo:  DEFAULT_PHOTO,
  char:   'boy',  // 'boy' | 'girl'
  id:     ''      // généré automatiquement
};

// Précharger la photo exemple
const _defaultImg = new Image();
_defaultImg.onload = () => { playerData._photoImg = _defaultImg; };
_defaultImg.src = DEFAULT_PHOTO;

function generateId() {
  const letters = 'ABCDEFGHJKLMNPQRSTUVWXYZ';
  const nums    = '0123456789';
  let id = '';
  for (let i = 0; i < 3; i++) id += nums[Math.floor(Math.random() * 10)];
  id += letters[Math.floor(Math.random() * letters.length)];
  id += letters[Math.floor(Math.random() * letters.length)];
  id += letters[Math.floor(Math.random() * letters.length)];
  for (let i = 0; i < 4; i++) id += nums[Math.floor(Math.random() * 10)];
  return id;
}

// ══════════════════════════════════════════════════
//  DESSIN DE LA CARTE ÉTUDIANT (canvas)
// ══════════════════════════════════════════════════
function drawStudentCard(c, w, h, data) {
  const r = w / 340; // ratio pour adapter la taille

  // Fond blanc
  c.fillStyle = '#f8f8f8';
  c.fillRect(0, 0, w, h);

  // Triangles décoratifs gris ESPRIT (fond)
  c.fillStyle = 'rgba(180,180,180,0.12)';
  [[w*0.55, h*0.1, w*0.35],[w*0.72, h*0.5, w*0.22],[w*0.42, h*0.6, w*0.18]].forEach(([tx,ty,ts]) => {
    c.beginPath(); c.moveTo(tx,ty); c.lineTo(tx+ts,ty); c.lineTo(tx+ts/2,ty-ts*0.8); c.closePath(); c.fill();
  });

  // Bandeau ORANGE "CARTE ÉTUDIANT" en haut à droite
  c.fillStyle = '#e67e22';
  c.fillRect(w*0.40, 0, w*0.60, h*0.22);
  c.fillStyle = 'white';
  c.font = `bold ${14*r}px 'DM Sans', sans-serif`;
  c.textAlign = 'center';
  c.fillText('CARTE ÉTUDIANT', w*0.70, h*0.14);
  c.textAlign = 'left';

  // Logo ESPRIT en haut à gauche
  c.font = `bold ${18*r}px 'Bebas Neue', sans-serif`;
  c.fillStyle = '#333';
  c.fillText('espr', w*0.04, h*0.16);
  const espW = c.measureText('espr').width;
  c.fillStyle = '#666';
  c.fillText('it', w*0.04 + espW, h*0.16);
  c.fillStyle = '#e67e22';
  c.font = `bold ${13*r}px sans-serif`;
  c.fillText('▶', w*0.04 + espW + c.measureText('it').width + 2, h*0.15);

  // Sous-titre logo
  c.fillStyle = '#888';
  c.font = `${7*r}px 'DM Sans', sans-serif`;
  c.fillText('Se former autrement', w*0.04, h*0.24);
  c.fillText('HONORIS UNITED UNIVERSITIES', w*0.04, h*0.31);

  // Ligne séparatrice rouge
  c.fillStyle = '#c0392b';
  c.fillRect(w*0.04, h*0.34, w*0.92, 2);

  // Année universitaire (orange)
  c.fillStyle = '#e67e22';
  c.font = `bold ${8*r}px 'DM Sans', sans-serif`;
  c.textAlign = 'right';
  c.fillText('Année universitaire 2025 / 2026', w*0.96, h*0.29);
  c.textAlign = 'left';

  // Infos texte
  const lineH = h * 0.13;
  const labels = [
    ['NOM :', data.nom   ? data.nom.toUpperCase()   : '—'],
    ['PRÉNOM :', data.prenom ? data.prenom          : '—'],
    ['CLASSE :', data.classe ? data.classe.toUpperCase() : '—'],
    ['IDENTIFIANT :', data.id || '—'],
  ];
  c.font = `bold ${9*r}px 'DM Sans', sans-serif`;
  labels.forEach(([lbl, val], i) => {
    const y = h*0.44 + i * lineH;
    c.fillStyle = '#333';
    c.font = `bold ${8.5*r}px 'DM Sans', sans-serif`;
    c.fillText(lbl, w*0.04, y);
    c.fillStyle = '#111';
    c.font = `bold ${9.5*r}px 'DM Sans', sans-serif`;
    c.fillText(val, w*0.04 + 70*r, y);
  });

  // Badge spécialité
  c.fillStyle = '#c0392b';
  c.fillRect(w*0.04, h*0.88, 80*r, 14*r);
  c.fillStyle = 'white';
  c.font = `bold ${7*r}px 'DM Sans', sans-serif`;
  c.textAlign = 'center';
  c.fillText(data.spec || 'GamiX', w*0.04 + 40*r, h*0.88 + 10*r);
  c.textAlign = 'left';

  // Cadre photo (droite) — style carte ESPRIT avec bordures orange/rouge
  const photoX = w * 0.63;
  const photoY = h * 0.36;
  const photoW = w * 0.31;
  const photoH = h * 0.52;

  // Bordures décoratives orange/rouge
  const bw = 5 * r;
  const colors = ['#e67e22','#c0392b','#f39c12','#e74c3c'];
  // Haut
  c.fillStyle = colors[0]; c.fillRect(photoX - bw*1.5, photoY - bw*1.5, photoW*0.4, bw);
  c.fillStyle = colors[1]; c.fillRect(photoX + photoW*0.6, photoY - bw*1.5, photoW*0.4 + bw*1.5, bw);
  // Bas
  c.fillStyle = colors[2]; c.fillRect(photoX - bw*1.5, photoY + photoH + bw*0.5, photoW*0.45, bw);
  c.fillStyle = colors[3]; c.fillRect(photoX + photoW*0.55, photoY + photoH + bw*0.5, photoW*0.45 + bw*1.5, bw);
  // Gauche
  c.fillStyle = colors[1]; c.fillRect(photoX - bw*1.5, photoY, bw, photoH*0.4);
  c.fillStyle = colors[0]; c.fillRect(photoX - bw*1.5, photoY + photoH*0.6, bw, photoH*0.4);
  // Droite
  c.fillStyle = colors[2]; c.fillRect(photoX + photoW + bw*0.5, photoY, bw, photoH*0.4);
  c.fillStyle = colors[3]; c.fillRect(photoX + photoW + bw*0.5, photoY + photoH*0.6, bw, photoH*0.4);

  // Zone photo
  c.fillStyle = '#ddd';
  c.fillRect(photoX, photoY, photoW, photoH);

  if (data.photo && data._photoImg) {
    // Photo uploadée
    try {
      c.save();
      c.beginPath();
      c.rect(photoX, photoY, photoW, photoH);
      c.clip();
      // Centrer et couvrir
      const img = data._photoImg;
      const scale = Math.max(photoW / img.width, photoH / img.height);
      const iw = img.width * scale, ih = img.height * scale;
      c.drawImage(img, photoX + (photoW - iw)/2, photoY + (photoH - ih)/2, iw, ih);
      c.restore();
    } catch(e) {
      drawAvatarInCard(c, photoX, photoY, photoW, photoH, data.char);
    }
  } else {
    // Avatar généré selon le personnage
    drawAvatarInCard(c, photoX, photoY, photoW, photoH, data.char);
  }

  // Ligne pointillée rouge en bas (style carte ESPRIT)
  c.strokeStyle = '#c0392b';
  c.lineWidth = 1.5;
  c.setLineDash([4, 3]);
  c.beginPath();
  c.moveTo(w*0.04, h*0.95);
  c.lineTo(w*0.96, h*0.95);
  c.stroke();
  c.setLineDash([]);
}

function drawAvatarInCard(c, x, y, w, h, charType) {
  // Fond
  c.fillStyle = charType === 'girl' ? '#fdf2f8' : '#eaf4fb';
  c.fillRect(x, y, w, h);

  const cx = x + w/2, cy = y + h/2;
  const scale = Math.min(w, h) / 80;

  // Corps
  c.fillStyle = charType === 'girl' ? '#922b21' : '#c0392b';
  c.fillRect(cx - 14*scale, cy - 5*scale, 28*scale, 25*scale);

  // ESPRIT
  c.fillStyle = 'rgba(255,255,255,0.7)';
  c.font = `bold ${5*scale}px sans-serif`;
  c.textAlign = 'center';
  c.fillText('ESPRIT', cx, cy + 10*scale);

  // Tête
  c.fillStyle = '#f0c8a0';
  c.beginPath();
  c.arc(cx, cy - 18*scale, 13*scale, 0, Math.PI*2);
  c.fill();

  // Cheveux
  c.fillStyle = '#2c1a0e';
  if (charType === 'girl') {
    c.beginPath(); c.arc(cx, cy - 22*scale, 12*scale, Math.PI, 0); c.fill();
    c.fillRect(cx - 12*scale, cy - 30*scale, 24*scale, 10*scale);
    c.fillRect(cx - 14*scale, cy - 22*scale, 5*scale, 14*scale);
    c.fillRect(cx + 9*scale, cy - 22*scale, 5*scale, 14*scale);
  } else {
    c.beginPath(); c.arc(cx, cy - 23*scale, 11*scale, Math.PI, 0); c.fill();
    c.fillRect(cx - 11*scale, cy - 30*scale, 22*scale, 9*scale);
  }

  // Yeux
  c.fillStyle = '#333';
  c.fillRect(cx - 6*scale, cy - 20*scale, 3*scale, 4*scale);
  c.fillRect(cx + 3*scale, cy - 20*scale, 3*scale, 4*scale);

  // Sourire
  c.strokeStyle = '#a0522d'; c.lineWidth = 1.2*scale;
  c.beginPath(); c.arc(cx, cy - 13*scale, 4*scale, 0, Math.PI); c.stroke();

  c.textAlign = 'left';
}

// ══════════════════════════════════════════════════
//  LOGIQUE DU FORMULAIRE
// ══════════════════════════════════════════════════

const cardCanvas    = document.getElementById('cardCanvas');
const cardCtx       = cardCanvas.getContext('2d');
let selectedCharType = 'boy';

function refreshCardPreview() {
  drawStudentCard(cardCtx, cardCanvas.width, cardCanvas.height, {
    ...playerData,
    nom:    document.getElementById('fieldNom').value,
    prenom: document.getElementById('fieldPrenom').value,
    classe: document.getElementById('fieldClasse').value,
    spec:   document.getElementById('fieldSpec').value,
    char:   selectedCharType,
    id:     playerData.id || '???'
  });
}

function checkFormValidity() {
  const nom    = document.getElementById('fieldNom').value.trim();
  const prenom = document.getElementById('fieldPrenom').value.trim();
  const btn    = document.getElementById('confirmCardBtn');
  if (nom && prenom) {
    btn.disabled = false;
  } else {
    btn.disabled = true;
  }
  refreshCardPreview();
}

// Inputs → mise à jour live
['fieldNom','fieldPrenom','fieldClasse','fieldSpec'].forEach(id => {
  document.getElementById(id).addEventListener('input', checkFormValidity);
});

// Photo upload
// Afficher "photo exemple" au chargement
document.getElementById('photoName').textContent = '📸 Photo exemple (remplaçable)';
document.getElementById('photoName').style.color = '#e67e22';

document.getElementById('photoInput').addEventListener('change', function() {
  const file = this.files[0];
  if (!file) return;
  document.getElementById('photoName').textContent = '✅ ' + file.name;
  document.getElementById('photoName').style.color = '#27ae60';
  const reader = new FileReader();
  reader.onload = e => {
    playerData.photo = e.target.result;
    const img = new Image();
    img.onload = () => {
      playerData._photoImg = img;
      refreshCardPreview();
    };
    img.src = e.target.result;
  };
  reader.readAsDataURL(file);
});

// Sélection personnage
window.pickChar = function(type) {
  selectedCharType = type;
  document.getElementById('miniMale').classList.toggle('active',   type === 'boy');
  document.getElementById('miniFemale').classList.toggle('active', type === 'girl');
  refreshCardPreview();
  drawMiniPreviews();
};

function drawMiniPreviews() {
  ['boy','girl'].forEach(type => {
    const id = type === 'boy' ? 'miniCanvasBoy' : 'miniCanvasGirl';
    const mc = document.getElementById(id);
    const mctx = mc.getContext('2d');
    mctx.clearRect(0, 0, mc.width, mc.height);
    mctx.fillStyle = selectedCharType === type ? '#fff5f5' : '#f5f2ef';
    mctx.fillRect(0, 0, mc.width, mc.height);
    drawCharacter(mctx, mc.width/2 - 14, mc.height - 52 - 4, 28, 52,
                  CHARS[type], 1, 0, false);
  });
}

// Confirmer carte
document.getElementById('confirmCardBtn').addEventListener('click', () => {
  playerData.nom    = document.getElementById('fieldNom').value.trim().toUpperCase();
  playerData.prenom = document.getElementById('fieldPrenom').value.trim();
  playerData.classe = document.getElementById('fieldClasse').value.trim();
  playerData.spec   = document.getElementById('fieldSpec').value;
  playerData.char   = selectedCharType;
  playerData.id     = generateId();

  // Dessiner la carte finale
  const fc = document.getElementById('cardFinalCanvas');
  const fctx = fc.getContext('2d');
  drawStudentCard(fctx, fc.width, fc.height, playerData);

  document.getElementById('playerFirstName').textContent = playerData.prenom;
  document.getElementById('cardScreen').style.display    = 'none';
  document.getElementById('cardShowScreen').style.display = 'flex';
});

document.getElementById('playNowBtn').addEventListener('click', () => {
  document.getElementById('cardShowScreen').style.display = 'none';
  score = 0; lives = 3;
  initZone(1);
  state = 'playing';
});

document.getElementById('editCardBtn').addEventListener('click', () => {
  document.getElementById('cardShowScreen').style.display = 'none';
  document.getElementById('cardScreen').style.display     = 'flex';
});

document.getElementById('startBtn').addEventListener('click', () => {
  document.getElementById('startScreen').style.display = 'none';
  document.getElementById('cardScreen').style.display  = 'flex';
  playerData.id = generateId();
  refreshCardPreview();
  drawMiniPreviews();
  // Sélectionner garçon par défaut
  pickChar('boy');
});

document.getElementById('changeCardBtn')?.addEventListener('click', () => {
  document.getElementById('gameOverScreen').style.display = 'none';
  document.getElementById('cardScreen').style.display     = 'flex';
  refreshCardPreview();
});

// ══════════════════════════════════════════════════
//  PERSONNAGES
// ══════════════════════════════════════════════════
const CHARS = {
  boy: {
    skinColor: '#f0c8a0', hairColor: '#2c1a0e',
    shirtColor: '#c0392b', pantsColor: '#2c3e50',
    shoeColor: '#1a1a1a', shoeAccent: '#c0392b',
    bagColor: '#1a252f', longHair: false,
    speedMult: 1.1, collectBonus: 0
  },
  girl: {
    skinColor: '#f5cba7', hairColor: '#1a0a00',
    shirtColor: '#922b21', pantsColor: '#5d6d7e',
    shoeColor: '#922b21', shoeAccent: '#ffffff',
    bagColor: '#6c3483', longHair: true,
    speedMult: 1.0, collectBonus: 5
  }
};

function drawCharacter(c, px, py, pw, ph, def, facing, walkFrame, speedBoost) {
  c.save();
  if (facing === -1) { c.translate(px+pw, py); c.scale(-1,1); px=0; py=0; }
  else               { c.translate(px, py);    px=0; py=0; }

  const legOff = Math.sin(walkFrame * Math.PI * 0.5) * 7;

  c.fillStyle = 'rgba(0,0,0,0.1)';
  c.beginPath(); c.ellipse(pw/2, ph+2, pw/2, 4, 0, 0, Math.PI*2); c.fill();

  // Jambes
  c.fillStyle = def.pantsColor;
  c.fillRect(3, ph*0.78+legOff, 10, ph*0.22);
  c.fillRect(pw-13, ph*0.78-legOff, 10, ph*0.22);

  // Chaussures
  c.fillStyle = def.shoeColor;
  c.fillRect(1, ph*0.95+legOff, 13, 7);
  c.fillRect(pw-14, ph*0.95-legOff, 13, 7);
  c.fillStyle = def.shoeAccent;
  c.fillRect(1, ph*0.95+legOff+4, 13, 3);
  c.fillRect(pw-14, ph*0.95-legOff+4, 13, 3);

  // Corps
  c.fillStyle = def.shirtColor;
  c.fillRect(4, ph*0.38, pw-8, ph*0.42);
  c.fillStyle = 'rgba(255,255,255,0.7)';
  c.font = `bold ${Math.max(5, pw*0.22)}px Bebas Neue, sans-serif`;
  c.textAlign = 'center';
  c.fillText('ESPRIT', pw/2, ph*0.58);
  c.textAlign = 'left';

  // Bras
  const armOff = Math.sin(walkFrame * Math.PI * 0.5) * 5;
  c.fillStyle = def.shirtColor;
  c.fillRect(-5, ph*0.4+armOff, 8, ph*0.28);
  c.fillRect(pw-3, ph*0.4-armOff, 8, ph*0.28);
  c.fillStyle = def.skinColor;
  c.beginPath(); c.arc(-3, ph*0.68+armOff, 5, 0, Math.PI*2); c.fill();
  c.beginPath(); c.arc(pw+1, ph*0.68-armOff, 5, 0, Math.PI*2); c.fill();

  // Tête
  c.fillStyle = def.skinColor;
  c.beginPath(); c.arc(pw/2, ph*0.22, pw*0.36, 0, Math.PI*2); c.fill();

  // Cheveux
  c.fillStyle = def.hairColor;
  if (def.longHair) {
    c.beginPath(); c.arc(pw/2, ph*0.16, pw*0.32, Math.PI, 0); c.fill();
    c.fillRect(pw/2-pw*0.32, ph*0.08, pw*0.64, ph*0.15);
    c.fillRect(-2, ph*0.18, 7, ph*0.3);
    c.fillRect(pw-5, ph*0.18, 7, ph*0.3);
  } else {
    c.beginPath(); c.arc(pw/2, ph*0.15, pw*0.3, Math.PI, 0); c.fill();
    c.fillRect(pw/2-pw*0.3, ph*0.08, pw*0.6, ph*0.14);
  }

  // Yeux
  c.fillStyle = '#222';
  c.fillRect(pw/2-8, ph*0.18, 4, 5);
  c.fillRect(pw/2+4, ph*0.18, 4, 5);
  c.fillStyle = '#fff';
  c.fillRect(pw/2-7, ph*0.18, 2, 2);
  c.fillRect(pw/2+5, ph*0.18, 2, 2);

  // Sourire
  c.strokeStyle = '#a0522d'; c.lineWidth = 1.2;
  c.beginPath(); c.arc(pw/2, ph*0.27, 4, 0, Math.PI); c.stroke();

  // Sac
  c.fillStyle = def.bagColor;
  c.fillRect(pw-2, ph*0.35, 8, ph*0.32);
  c.fillStyle = 'rgba(255,255,255,0.15)';
  c.fillRect(pw-1, ph*0.38, 6, ph*0.12);

  if (speedBoost) { c.font='12px serif'; c.fillText('⚡', pw+8, ph*0.1); }
  c.restore();
}

// ══════════════════════════════════════════════════
//  JEU
// ══════════════════════════════════════════════════
let state = 'idle';
let score = 0, lives = 3, currentZone = 1;
let collected = 0;
let keys = {}, particles = [], floatingTexts = [];
let cameraX = 0;

const zones = [
  { id:1, name:'📍 HALL D\'ENTRÉE',     totalItems:8,  bgTheme:'hall',     profCount:1, profSpeed:0.8, obstacleCount:3, worldWidth:2200 },
  { id:2, name:'🚪 COULOIR DES SALLES', totalItems:10, bgTheme:'corridor', profCount:2, profSpeed:1.2, obstacleCount:5, worldWidth:2800 },
  { id:3, name:'🔧 ATELIER WORKSHOP',   totalItems:12, bgTheme:'workshop', profCount:2, profSpeed:1.5, obstacleCount:6, worldWidth:3200 },
];

const COLLECTIBLES = [
  { type:'book',   emoji:'📚', label:'Livre',        pts:10, color:'#3498db' },
  { type:'laptop', emoji:'💻', label:'Laptop',       pts:20, color:'#2ecc71' },
  { type:'coffee', emoji:'☕', label:'Café',          pts:5,  color:'#e67e22', boost:true },
  { type:'badge',  emoji:'🎫', label:'Badge ESPRIT', pts:30, color:'#c0392b' },
];
const OBSTACLES = [
  { type:'chair', emoji:'🪑', label:'Chaise',  w:36, h:36 },
  { type:'bag',   emoji:'🎒', label:'Cartable',w:32, h:30 },
  { type:'cone',  emoji:'🚧', label:'Panneau', w:30, h:34 },
];

let worldWidth=2200, player, profs, items, obstacles;
let jumpCooldown=0, collectCooldown=0, zoneConfig;

function groundY() { return H - 80; }

function initZone(zoneId) {
  currentZone = zoneId;
  zoneConfig  = zones[zoneId - 1];
  worldWidth  = zoneConfig.worldWidth;
  cameraX = 0; collected = 0;
  particles = []; floatingTexts = [];

  const def       = CHARS[playerData.char];
  const baseSpeed = 3.2 * def.speedMult;

  player = { x:80, y:0, w:28, h:52, vx:0, vy:0, onGround:false,
             facing:1, walkFrame:0, walkTimer:0, invincible:0,
             speedBoost:0, baseSpeed };
  player.y = groundY() - player.h;

  profs = [];
  for (let i = 0; i < zoneConfig.profCount; i++) {
    let px = 500 + i*700 + Math.random()*300;
    profs.push({ x:px, y:groundY()-54, w:30, h:54,
                 dx:zoneConfig.profSpeed*(i%2===0?1:-1),
                 patrolLeft:px-150, patrolRight:px+150,
                 walkFrame:0, walkTimer:0 });
  }

  items = [];
  let sp = (worldWidth-300)/zoneConfig.totalItems;
  for (let i=0; i<zoneConfig.totalItems; i++) {
    let cDef = COLLECTIBLES[i%5===4 ? 3 : Math.floor(Math.random()*COLLECTIBLES.length)];
    items.push({ x:250+i*sp+Math.random()*80, y:groundY()-60-Math.random()*40,
                 w:36, h:36, def:cDef, collected:false, bobOffset:Math.random()*Math.PI*2 });
  }

  obstacles = [];
  let osp = (worldWidth-400)/zoneConfig.obstacleCount;
  for (let i=0; i<zoneConfig.obstacleCount; i++) {
    let oDef = OBSTACLES[Math.floor(Math.random()*OBSTACLES.length)];
    obstacles.push({ x:350+i*osp+Math.random()*100, y:groundY()-oDef.h, w:oDef.w, h:oDef.h, def:oDef });
  }

  updateHUD();
  document.getElementById('levelLabel').textContent  = zoneConfig.name;
  document.getElementById('collectTotal').textContent = zoneConfig.totalItems;
  document.getElementById('collectCount').textContent = 0;
}

function update() {
  if (state !== 'playing') return;
  const GRAVITY=0.55, JUMP=-13, GROUND=groundY();
  const SPEED = player.speedBoost>0 ? player.baseSpeed*1.4 : player.baseSpeed;

  if (keys['ArrowLeft']||keys['a'])       { player.vx=-SPEED; player.facing=-1; }
  else if (keys['ArrowRight']||keys['d']) { player.vx= SPEED; player.facing= 1; }
  else player.vx=0;

  if ((keys['ArrowUp']||keys['w']) && player.onGround && jumpCooldown===0) {
    player.vy=JUMP; player.onGround=false; jumpCooldown=14;
    spawnParticles(player.x+player.w/2, player.y+player.h, '#c0392b', 6);
  }
  if (jumpCooldown>0) jumpCooldown--;

  player.vy += GRAVITY;
  player.x  += player.vx;
  player.y  += player.vy;

  if (player.y+player.h >= GROUND) { player.y=GROUND-player.h; player.vy=0; player.onGround=true; }
  player.x = Math.max(0, Math.min(worldWidth-player.w, player.x));

  if (player.vx!==0 && player.onGround) {
    player.walkTimer++;
    if (player.walkTimer>8) { player.walkFrame=(player.walkFrame+1)%4; player.walkTimer=0; }
  }
  if (player.speedBoost>0) player.speedBoost--;
  if (player.invincible>0) player.invincible--;

  cameraX += (player.x - W/2.5 - cameraX) * 0.08;
  cameraX = Math.max(0, Math.min(worldWidth-W, cameraX));

  profs.forEach(p => {
    p.x += p.dx;
    if (p.x<=p.patrolLeft || p.x+p.w>=p.patrolRight) p.dx*=-1;
    p.walkTimer++; if (p.walkTimer>10) { p.walkFrame=(p.walkFrame+1)%2; p.walkTimer=0; }
    if (player.invincible===0 && rectsOverlap(player,p)) {
      player.invincible=90; lives--;
      updateHUD();
      spawnParticles(player.x+player.w/2, player.y+player.h/2, '#e74c3c', 16);
      addFloat('AÏE ! -1 ♥', player.x, player.y-20, '#e74c3c');
      if (lives<=0) { state='gameover'; showGameOver(); }
    }
  });

  if (collectCooldown>0) collectCooldown--;
  if ((keys[' ']||keys['Space']) && collectCooldown===0) {
    items.forEach(item => {
      if (item.collected) return;
      if (Math.hypot((item.x+item.w/2)-(player.x+player.w/2),(item.y+item.h/2)-(player.y+player.h/2))<70)
        collectItem(item);
    });
    collectCooldown=8;
  }
  items.forEach(item => {
    if (!item.collected && rectsOverlap(player,{x:item.x,y:item.y-10,w:item.w,h:item.h+10}))
      collectItem(item);
  });

  obstacles.forEach(obs => {
    if (player.vy>0 && rectsOverlap(player,obs)) {
      if (player.y+player.h-player.vy <= obs.y+4) {
        player.y=obs.y-player.h; player.vy=0; player.onGround=true;
      } else if (player.invincible===0) {
        player.vx=-player.vx*2; player.invincible=30; lives--;
        updateHUD(); addFloat('AÏE !', player.x, player.y-20, '#e74c3c');
        if (lives<=0) { state='gameover'; showGameOver(); }
      }
    }
  });

  items.forEach(i => i.bobOffset+=0.05);
  floatingTexts = floatingTexts.filter(t => { t.y-=1.2; t.life-=0.02; return t.life>0; });
  particles     = particles.filter(p  => { p.x+=p.vx; p.y+=p.vy; p.vy+=0.15; p.life-=0.04; return p.life>0; });

  if (collected>=zoneConfig.totalItems) { state='levelclear'; showLevelClear(); }
}

function collectItem(item) {
  item.collected=true; collected++;
  const bonus = CHARS[playerData.char].collectBonus;
  const pts   = item.def.pts + bonus;
  score += pts;
  if (item.def.boost) player.speedBoost=180;
  spawnParticles(item.x+item.w/2, item.y+item.h/2, item.def.color, 10);
  addFloat('+'+pts+(bonus>0?` +${bonus}✨`:''), item.x, item.y-10, item.def.color);
  updateHUD();
  document.getElementById('collectCount').textContent = collected;
}

function rectsOverlap(a,b) { return a.x<b.x+b.w && a.x+a.w>b.x && a.y<b.y+b.h && a.y+a.h>b.y; }

// ── DRAW ─────────────────────────────────────────────
function draw() {
  ctx.clearRect(0,0,W,H);
  ctx.save();
  ctx.translate(-Math.floor(cameraX),0);
  drawBackground(); drawFloor(); drawItems(); drawObstacles(); drawProfs();
  if (state==='playing') {
    const def = CHARS[playerData.char];
    if (player.invincible===0 || Math.floor(player.invincible/5)%2!==0)
      drawCharacter(ctx, player.x, player.y, player.w, player.h, def, player.facing, player.walkFrame, player.speedBoost>0);
  }
  ctx.restore();
  drawParticles(); drawFloatingTexts(); drawProgressBar();

  // Mini carte dans le coin
  if (state==='playing') {
    const mc = document.createElement('canvas');
    mc.width=90; mc.height=56;
    drawStudentCard(mc.getContext('2d'), 90, 56, playerData);
    ctx.save();
    ctx.globalAlpha=0.92;
    ctx.drawImage(mc, W-98, 8);
    ctx.globalAlpha=1;
    ctx.strokeStyle='rgba(192,57,43,0.6)'; ctx.lineWidth=1;
    ctx.strokeRect(W-98, 8, 90, 56);
    ctx.restore();
  }
}

function drawBackground() {
  const theme = zoneConfig?zoneConfig.bgTheme:'hall';
  const WW = worldWidth;
  if (theme==='hall') {
    ctx.fillStyle='#f7f5f2'; ctx.fillRect(0,0,WW,H-80);
    ctx.fillStyle='#c0392b'; ctx.fillRect(0,H*0.55,WW,8);
    ctx.fillStyle='#c8c4bf'; ctx.fillRect(0,H*0.55+8,WW,H-80-H*0.55-8);
    for (let tx=100;tx<WW;tx+=280) drawESPRITTriangles(tx,60);
    for (let lx=300;lx<WW;lx+=600) { ctx.font='bold 32px Bebas Neue,sans-serif'; ctx.fillStyle='rgba(0,0,0,0.1)'; ctx.fillText('esprit',lx,80); }
    for (let wx=150;wx<WW;wx+=320) drawWindow(wx,40);
    for (let dx=200;dx<WW;dx+=350) drawDoor(dx,H*0.55-120);
  } else if (theme==='corridor') {
    ctx.fillStyle='#252525'; ctx.fillRect(0,0,WW,H-80);
    ctx.fillStyle='#1a1a1a'; ctx.fillRect(0,H*0.6,WW,H-80-H*0.6);
    for (let lx=80;lx<WW;lx+=200) {
      ctx.fillStyle='#fffde7'; ctx.fillRect(lx,5,100,18);
      let h2=ctx.createRadialGradient(lx+50,30,0,lx+50,30,120);
      h2.addColorStop(0,'rgba(255,253,200,0.18)'); h2.addColorStop(1,'rgba(0,0,0,0)');
      ctx.fillStyle=h2; ctx.fillRect(lx-70,0,240,200);
    }
    for (let sx=180;sx<WW;sx+=280) drawRoomSign(sx,H*0.2);
    for (let dx=120;dx<WW;dx+=280) drawDoor(dx,H*0.35);
    ctx.fillStyle='#c0392b'; ctx.fillRect(0,H*0.6,WW,5);
  } else {
    ctx.fillStyle='#2a2520'; ctx.fillRect(0,0,WW,H-80);
    for (let gx=100;gx<WW;gx+=500) drawWorkshopDoor(gx,H*0.1);
    for (let sx=200;sx<WW;sx+=600) { ctx.fillStyle='#1a1a1a'; ctx.fillRect(sx,30,200,50); ctx.font='bold 16px Bebas Neue,sans-serif'; ctx.fillStyle='#c0392b'; ctx.fillText('WORKSHOPS',sx+8,52); }
    for (let lx=60;lx<WW;lx+=160) { ctx.fillStyle='#fff9e6'; ctx.fillRect(lx,0,60,12); }
  }
}
function drawESPRITTriangles(x,y) {
  [{dx:0,dy:0,s:22,c:'#c0392b'},{dx:28,dy:-10,s:16,c:'#e74c3c'},{dx:50,dy:8,s:12,c:'#922b21'},{dx:-15,dy:20,s:10,c:'#e0d0d0'}].forEach(t=>{
    ctx.fillStyle=t.c; ctx.beginPath(); ctx.moveTo(x+t.dx,y+t.dy); ctx.lineTo(x+t.dx+t.s,y+t.dy); ctx.lineTo(x+t.dx+t.s/2,y+t.dy-t.s*0.8); ctx.closePath(); ctx.fill();
  });
}
function drawWindow(x,y) {
  ctx.fillStyle='#b8d4e8'; ctx.fillRect(x,y,80,60);
  ctx.strokeStyle='#999'; ctx.lineWidth=2; ctx.strokeRect(x,y,80,60);
  ctx.strokeStyle='#aaa'; ctx.lineWidth=1;
  ctx.beginPath(); ctx.moveTo(x+40,y); ctx.lineTo(x+40,y+60); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(x,y+30); ctx.lineTo(x+80,y+30); ctx.stroke();
  ctx.fillStyle='rgba(255,255,255,0.3)'; ctx.fillRect(x+4,y+4,16,24);
}
function drawDoor(x,y) {
  ctx.fillStyle='#8B6914'; ctx.fillRect(x,y,55,110);
  ctx.fillStyle='#a0782a'; ctx.fillRect(x+4,y+4,47,102);
  ctx.fillStyle='#d4af37'; ctx.beginPath(); ctx.arc(x+42,y+58,5,0,Math.PI*2); ctx.fill();
  ctx.fillStyle='rgba(180,220,240,0.5)'; ctx.fillRect(x+10,y+10,35,40);
}
function drawRoomSign(x,y) {
  ctx.fillStyle='#f0f0f0'; ctx.fillRect(x,y,120,80);
  ctx.strokeStyle='#ccc'; ctx.lineWidth=1; ctx.strokeRect(x,y,120,80);
  ['YOURROBOT','ROB & ROID','AERO ESPRIT'].forEach((l,i)=>{
    ctx.font='9px DM Sans,sans-serif'; ctx.fillStyle='#333'; ctx.fillText('· '+l,x+8,y+22+i*22);
  });
}
function drawWorkshopDoor(x,y) {
  ctx.fillStyle='#5a5a5a'; ctx.fillRect(x,y,120,H*0.5);
  for (let gy=y+10;gy<y+H*0.5;gy+=30) for (let gx=x+10;gx<x+120;gx+=30) {
    ctx.strokeStyle='#444'; ctx.lineWidth=1;
    ctx.beginPath(); ctx.moveTo(gx+15,gy); ctx.lineTo(gx+30,gy+15); ctx.lineTo(gx+15,gy+30); ctx.lineTo(gx,gy+15); ctx.closePath(); ctx.stroke();
  }
}
function drawFloor() {
  const theme=zoneConfig?zoneConfig.bgTheme:'hall'; const WW=worldWidth; const GY=groundY();
  if (theme==='hall') {
    ctx.fillStyle='#d4cfc8'; ctx.fillRect(0,GY,WW,H-GY);
    ctx.strokeStyle='#bbb'; ctx.lineWidth=0.5;
    for (let tx=0;tx<WW;tx+=60){ctx.beginPath();ctx.moveTo(tx,GY);ctx.lineTo(tx,H);ctx.stroke();}
    for (let ty=GY;ty<H;ty+=60){ctx.beginPath();ctx.moveTo(0,ty);ctx.lineTo(WW,ty);ctx.stroke();}
    let ref=ctx.createLinearGradient(0,GY,0,GY+30); ref.addColorStop(0,'rgba(255,255,255,0.3)'); ref.addColorStop(1,'rgba(255,255,255,0)');
    ctx.fillStyle=ref; ctx.fillRect(0,GY,WW,30);
  } else if (theme==='corridor') {
    ctx.fillStyle='#1e1e1e'; ctx.fillRect(0,GY,WW,H-GY);
  } else {
    ctx.fillStyle='#302820'; ctx.fillRect(0,GY,WW,H-GY);
  }
}
function drawItems() {
  const t=Date.now()*0.001;
  items.forEach(item=>{
    if (item.collected) return;
    const bobY=Math.sin(t*2+item.bobOffset)*5;
    const sx=item.x-cameraX; if (sx<-50||sx>W+50) return;
    if (item.def.type==='badge') {
      let halo=ctx.createRadialGradient(item.x+item.w/2,item.y+bobY+item.h/2,0,item.x+item.w/2,item.y+bobY+item.h/2,28);
      halo.addColorStop(0,'rgba(192,57,43,0.25)'); halo.addColorStop(1,'rgba(192,57,43,0)');
      ctx.fillStyle=halo; ctx.beginPath(); ctx.arc(item.x+item.w/2,item.y+bobY+item.h/2,28,0,Math.PI*2); ctx.fill();
    }
    ctx.fillStyle=item.def.color+'33'; ctx.strokeStyle=item.def.color; ctx.lineWidth=2;
    ctx.beginPath(); ctx.arc(item.x+item.w/2,item.y+bobY+item.h/2,20,0,Math.PI*2); ctx.fill(); ctx.stroke();
    ctx.font='22px serif'; ctx.textAlign='center'; ctx.textBaseline='middle';
    ctx.fillText(item.def.emoji,item.x+item.w/2,item.y+bobY+item.h/2);
    ctx.font='9px DM Sans,sans-serif'; ctx.textBaseline='alphabetic';
    ctx.fillStyle=item.def.color;
    ctx.fillText(item.def.label,item.x+item.w/2,item.y+bobY+item.h+14);
    ctx.fillText('+'+item.def.pts,item.x+item.w/2,item.y+bobY+item.h+24);
    ctx.textAlign='left';
  });
}
function drawObstacles() {
  obstacles.forEach(obs=>{
    const sx=obs.x-cameraX; if (sx<-60||sx>W+60) return;
    ctx.fillStyle='rgba(0,0,0,0.12)'; ctx.fillRect(obs.x+4,obs.y+obs.h-4,obs.w,6);
    ctx.font='28px serif'; ctx.textAlign='center'; ctx.textBaseline='bottom';
    ctx.fillText(obs.def.emoji,obs.x+obs.w/2,obs.y+obs.h+2);
    ctx.font='9px DM Sans,sans-serif'; ctx.fillStyle='#888';
    ctx.fillText('⚠ '+obs.def.label,obs.x+obs.w/2,obs.y+obs.h+16);
    ctx.textAlign='left'; ctx.textBaseline='alphabetic';
  });
}
function drawProfs() {
  profs.forEach(p=>{
    const sx=p.x-cameraX; if (sx<-80||sx>W+80) return;
    ctx.save();
    if (p.dx<0){ctx.translate(p.x+p.w,p.y);ctx.scale(-1,1);}else{ctx.translate(p.x,p.y);}
    const wk=p.walkFrame;
    ctx.fillStyle='rgba(0,0,0,0.12)'; ctx.beginPath(); ctx.ellipse(p.w/2,p.h+2,p.w/2,4,0,0,Math.PI*2); ctx.fill();
    ctx.fillStyle='#3d3d3d'; ctx.fillRect(6,p.h*0.38,p.w-12,p.h*0.45);
    ctx.fillStyle='#f0f0f0'; ctx.fillRect(10,p.h*0.4,p.w-20,p.h*0.38);
    ctx.fillStyle='#c0392b'; ctx.fillRect(p.w/2-3,p.h*0.4,6,p.h*0.35);
    ctx.fillStyle='#f0c8a0'; ctx.beginPath(); ctx.arc(p.w/2,p.h*0.2,p.w*0.32,0,Math.PI*2); ctx.fill();
    ctx.fillStyle='#555'; ctx.beginPath(); ctx.arc(p.w/2,p.h*0.14,p.w*0.28,Math.PI,0); ctx.fill();
    ctx.fillStyle='#333'; ctx.fillRect(p.w/2-7,p.h*0.18,4,4); ctx.fillRect(p.w/2+3,p.h*0.18,4,4);
    ctx.strokeStyle='#c0392b'; ctx.lineWidth=1.5; ctx.beginPath(); ctx.arc(p.w/2,p.h*0.25,5,0,Math.PI); ctx.stroke();
    const lo=Math.sin(wk*Math.PI)*8;
    ctx.fillStyle='#2c2c2c'; ctx.fillRect(7,p.h*0.82+lo,10,p.h*0.18); ctx.fillRect(p.w-17,p.h*0.82-lo,10,p.h*0.18);
    ctx.fillStyle='#1a1a1a'; ctx.fillRect(5,p.h*0.96+lo,14,6); ctx.fillRect(p.w-19,p.h*0.96-lo,14,6);
    ctx.fillStyle='#c0392b'; ctx.font='bold 8px DM Sans,sans-serif'; ctx.textAlign='center';
    ctx.fillText('🧑‍🏫 PROF',p.w/2,-6); ctx.textAlign='left';
    ctx.restore();
  });
}
function drawParticles() {
  particles.forEach(p=>{
    ctx.globalAlpha=p.life; ctx.fillStyle=p.color;
    ctx.beginPath(); ctx.arc(p.x-cameraX,p.y,p.size*p.life,0,Math.PI*2); ctx.fill();
  });
  ctx.globalAlpha=1;
}
function drawFloatingTexts() {
  floatingTexts.forEach(t=>{
    ctx.globalAlpha=t.life; ctx.font='bold 13px DM Sans,sans-serif';
    ctx.fillStyle=t.color; ctx.textAlign='center';
    ctx.fillText(t.text,t.x-cameraX,t.y);
  });
  ctx.globalAlpha=1; ctx.textAlign='left';
}
function drawProgressBar() {
  const prog=zoneConfig?collected/zoneConfig.totalItems:0;
  ctx.fillStyle='rgba(0,0,0,0.3)'; ctx.fillRect(0,0,W,5);
  ctx.fillStyle='#c0392b'; ctx.fillRect(0,0,W*prog,5);
}

function spawnParticles(x,y,color,count) {
  for (let i=0;i<count;i++){
    const a=Math.random()*Math.PI*2, s=1.5+Math.random()*3;
    particles.push({x,y,vx:Math.cos(a)*s,vy:Math.sin(a)*s-2,life:1,size:3+Math.random()*3,color});
  }
}
function addFloat(text,x,y,color) { floatingTexts.push({text,x,y,color,life:1}); }

function updateHUD() {
  document.getElementById('scoreDisplay').textContent = score;
  document.getElementById('livesDisplay').textContent = ['♥♥♥','♥♥♡','♥♡♡','♡♡♡'][Math.max(0,3-lives)];
}

function showLevelClear() {
  if (currentZone>=3) {
    document.getElementById('winScore').textContent = 'SCORE FINAL : '+score;
    document.getElementById('winMsg').textContent = `Bravo ${playerData.prenom} ! Tu as traversé toute l'école ESPRIT ! 🎓`;
    // Redessiner la carte sur l'écran de victoire
    const wc = document.getElementById('cardWinCanvas');
    drawStudentCard(wc.getContext('2d'), wc.width, wc.height, playerData);
    document.getElementById('winScreen').style.display='flex';
  } else {
    document.getElementById('levelClearTitle').textContent = '✅ ZONE '+currentZone+' TERMINÉE !';
    document.getElementById('levelClearDesc').textContent  = 'Tu passes à '+zones[currentZone].name;
    document.getElementById('levelScore').textContent      = 'Score : '+score;
    document.getElementById('levelScreen').style.display  = 'flex';
  }
}
function showGameOver() {
  document.getElementById('goScore').textContent = 'Score final : '+score;
  document.getElementById('goMsg').textContent   = `Aïe ${playerData.prenom} ! Le prof t'a eu… 😬`;
  document.getElementById('gameOverScreen').style.display='flex';
}

// ── BOUCLE ────────────────────────────────────────────
let lastTime=0;
function loop(ts) {
  requestAnimationFrame(loop);
  if (ts-lastTime<16) return;
  lastTime=ts; update(); draw();
}

// ── CONTRÔLES ─────────────────────────────────────────
document.addEventListener('keydown',e=>{ keys[e.key]=true; if(e.key===' ')e.preventDefault(); });
document.addEventListener('keyup',  e=>{ keys[e.key]=false; });

// ── GUIDE ─────────────────────────────────────────────
const guideOverlay=document.getElementById('guideOverlay');
document.getElementById('closeGuideBtn').onclick  = ()=>guideOverlay.classList.remove('visible');
document.getElementById('closeGuideBtn2').onclick = ()=>guideOverlay.classList.remove('visible');
guideOverlay.addEventListener('click',e=>{ if(e.target===guideOverlay) guideOverlay.classList.remove('visible'); });

// ── BOUTONS JEU ───────────────────────────────────────
document.getElementById('nextLevelBtn').onclick = ()=>{
  document.getElementById('levelScreen').style.display='none';
  initZone(currentZone+1); state='playing';
};
document.getElementById('restartBtn').onclick = ()=>{
  score=0; lives=3;
  document.getElementById('gameOverScreen').style.display='none';
  initZone(1); state='playing';
};
document.getElementById('winRestartBtn').onclick = ()=>{
  score=0; lives=3;
  document.getElementById('winScreen').style.display='none';
  initZone(1); state='playing';
};

// ── START ─────────────────────────────────────────────
requestAnimationFrame(loop);
